import type { Metadata } from "next";

import { LoginRegister } from "@/components/login-register";
import { getPublicPaidActionGates } from "@/lib/paid-action-gates";
import { createServerReadSupabaseClient } from "@/lib/supabase";
import type { PaidActionGates } from "@/lib/types";

export const dynamic = "force-dynamic";

export const metadata: Metadata = {
  title: "Join WorldCup26",
  description:
    "Use your referral invite, pick 3 teams, and climb the WorldCup26 leaderboard.",
  openGraph: {
    title: "You are invited to WorldCup26",
    description:
      "Pick 3 teams before the FIFA World Cup 2026 and climb the leaderboard with your invite.",
    url: "/login",
    type: "website",
  },
  twitter: {
    card: "summary_large_image",
    title: "You are invited to WorldCup26",
    description:
      "Use your referral invite, pick 3 teams, and climb the leaderboard.",
  },
};

type LoginPageProps = {
  searchParams?: Promise<{ ref?: string | string[] }> | { ref?: string | string[] };
};

export default async function LoginPage({ searchParams }: LoginPageProps) {
  const resolvedSearchParams = searchParams ? await searchParams : {};
  const refParam = Array.isArray(resolvedSearchParams.ref)
    ? resolvedSearchParams.ref[0]
    : resolvedSearchParams.ref;
  const publicPaidActionGates = await getPublicPaidActionGatesForLogin();

  return (
    <LoginRegister
      initialReferralCode={refParam ?? null}
      publicPaidActionGates={publicPaidActionGates}
    />
  );
}

async function getPublicPaidActionGatesForLogin(): Promise<PaidActionGates | undefined> {
  try {
    return await Promise.race([
      getPublicPaidActionGates(createServerReadSupabaseClient()),
      new Promise<undefined>((resolve) => setTimeout(() => resolve(undefined), 1500)),
    ]);
  } catch {
    return undefined;
  }
}
